class Solution(object):
    def mostFrequentEven(self, nums):
        from collections import Counter
        even_count = Counter(n for n in nums if n % 2 == 0)
        if not even_count:
            return -1
        max_freq = max(even_count.values())
        return min(n for n, c in even_count.items() if c == max_freq)
